     3→import React, { useState, useMemo, useRef, useEffect, useCallback } from "react";
     4→import useSWR, { mutate } from "swr";
     5→import Link from "next/link";
     6→import { useRouter } from "next/navigation";
     7→import {
     8→  projects as projectsApi,
     9→  releases as releasesApi,
    10→  sources as sourcesApi,
    11→  semanticReleases as srApi,
    12→} from "@/lib/api/client";
    13→import { getProviderIcon } from "@/components/ui/provider-badge";
    14→import { ProjectLogo } from "@/components/ui/project-logo";
    15→import { timeAgo } from "@/lib/format";
    16→import { Plus, ArrowRight, LayoutGrid, List, Search, Pencil, ArrowUpDown, Loader2, Info } from "lucide-react";
    17→import { SourceForm } from "@/components/sources/source-form";
    18→import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
    19→import { ProjectForm } from "@/components/projects/project-form";
    20→import type { Project, Source } from "@/lib/api/types";
    21→import { URGENCY_STYLES, URGENCY_COLORS } from "@/components/ui/urgency-pill";
    22→import { useTranslation } from "@/lib/i18n/context";
    23→
    24→/* ---------- Project Card Logo ---------- */
    25→
    26→function ProjectCardLogo({ projectId, name }: { projectId: string; name: string }) {
    27→  const { data } = useSWR(`project-${projectId}-card-sources`, () =>
    28→    sourcesApi.listByProject(projectId)
    29→  );
    30→  return <ProjectLogo name={name} sources={data?.data} size={40} />;
    31→}
    32→
    33→/* ---------- Overflow Flow ---------- */
    34→
    35→const LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
    36→const MAX_LINES = 2;
    37→const MAX_HEIGHT = LINE_HEIGHT * MAX_LINES;
    38→
    39→function FlowSection({
    40→  label,
    41→  moreHref,
    42→  moreLabel,
    43→  children,
    44→}: {
    45→  label: string;
    46→  moreHref: string;
    47→  moreLabel: string;
    48→  children: React.ReactNode;
    49→}) {
    50→  const measureRef = useRef<HTMLDivElement>(null);
    51→  const moreRef = useRef<HTMLSpanElement>(null);
    52→  const [visibleCount, setVisibleCount] = useState<number | null>(null);
    53→
    54→  const items = React.Children.toArray(children);
    55→
    56→  const measure = useCallback(() => {
    57→    const el = measureRef.current;
    58→    if (!el) return;
    59→    const nodes = el.children;
    60→    const itemNodeCount = nodes.length - 2; // exclude label (first) and hidden "more…" span (last)
    61→    // Check if everything fits without overflow
    62→    if (el.scrollHeight <= MAX_HEIGHT + 4) {
    63→      setVisibleCount(items.length);
    64→      return;
    65→    }
    66→    // Measure actual "more…" link width
    67→    const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 8 : 52;
    68→    const containerWidth = el.offsetWidth;
    69→    // First pass: find all items that fit within MAX_HEIGHT (2 lines)
    70→    let lastFitting = 0;
    71→    for (let i = 1; i <= itemNodeCount; i++) {
    72→      const node = nodes[i] as HTMLElement;
    73→      if (node.offsetTop + node.offsetHeight > MAX_HEIGHT) break;
    74→      lastFitting = i;
    75→    }
    76→    // Second pass: walk backward from lastFitting until "more…" fits after the item
    77→    let count = lastFitting;
    78→    while (count > 1) {
    79→      const node = nodes[count] as HTMLElement;
    80→      const nodeBottom = node.offsetTop + node.offsetHeight;
    81→      // If this item is on line 1, "more…" can always wrap to line 2 — we're fine
    82→      if (nodeBottom <= LINE_HEIGHT) break;
    83→      // Item is on line 2 — check if "more…" fits after it on the same line
    84→      const nodeRight = node.offsetLeft + node.offsetWidth;
    85→      if (nodeRight + moreWidth <= containerWidth) break;
    86→      count--;
    87→    }
    88→    setVisibleCount(Math.max(1, count));
    89→  }, [items.length]);
    90→
    91→  useEffect(() => {
    92→    const raf = requestAnimationFrame(measure);
    93→    const obs = new ResizeObserver(measure);
    94→    if (measureRef.current) obs.observe(measureRef.current);
    95→    return () => {
    96→      cancelAnimationFrame(raf);
    97→      obs.disconnect();
    98→    };
    99→  }, [measure, items.length]);
   100→
   101→  const hasOverflow = visibleCount !== null && visibleCount < items.length;
   102→  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;
   103→
   104→  return (
   105→    <div className="relative">
   106→      {/* Hidden measurer — renders all items to find cutoff */}
   107→      <div
   108→        ref={measureRef}
   109→        className="text-[13px] leading-7"
   110→        style={{ position: "absolute", visibility: "hidden", top: 0, left: 0, right: 0, pointerEvents: "none" }}
   111→        aria-hidden="true"
   112→      >
   113→        <span className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5">
   114→          {label}:
   115→        </span>
   116→        {items}
   117→        {/* Hidden "more…" to measure its actual width */}
   118→        <span ref={moreRef} className="inline-flex items-baseline text-[12px] font-medium whitespace-nowrap">
   119→          {moreLabel}
   120→        </span>
   121→      </div>
   122→      {/* Visible section */}
   123→      <div className="text-[13px] leading-7">
   124→        <span
   125→          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5 text-text-muted"
   126→          style={{ fontFamily: "var(--font-dm-sans)" }}
   127→        >
   128→          {label}:
   129→        </span>
   130→        {displayed}
   131→        {hasOverflow && (
   132→          <Link
   133→            href={moreHref}
   134→            className="inline-flex items-baseline text-[12px] font-medium hover:underline whitespace-nowrap text-beacon-accent"
   135→          >
   136→            {moreLabel}
   137→          </Link>
   138→        )}
   139→      </div>
   140→    </div>
   141→  );
   142→}
   143→
   144→/* ---------- Urgency Legend ---------- */
   145→
   146→function UrgencyLegend() {
   147→  const { t } = useTranslation();
   148→  const entries = [
   149→    { key: "critical", label: t("projects.urgency.critical"), desc: t("projects.urgency.criticalDesc") },
   150→    { key: "high", label: t("projects.urgency.high"), desc: t("projects.urgency.highDesc") },
   151→    { key: "medium", label: t("projects.urgency.medium"), desc: t("projects.urgency.mediumDesc") },
   152→    { key: "low", label: t("projects.urgency.low"), desc: t("projects.urgency.lowDesc") },
   153→  ] as const;
   154→
   155→  return (
   156→    <span className="relative inline-flex items-center group mr-1">
   157→      <Info size={11} className="cursor-help text-text-muted" />
   158→      <span
   159→        className="absolute left-0 top-full mt-1 z-50 hidden group-hover:block rounded-lg shadow-lg py-2 px-3 bg-surface border-border"
   160→        style={{ border: "1px solid var(--border)", width: 260 }}
   161→      >
   162→        <span className="block text-[10px] font-semibold uppercase tracking-wider mb-1.5 text-text-muted">
   163→          {t("projects.urgencyLegend")}
   164→        </span>
   165→        {entries.map(({ key, label, desc }) => {
   166→          const s = URGENCY_STYLES[key];
   167→          const Icon = s.icon;
   168→          return (
   169→            <span key={key} className="flex items-start gap-2 mb-1 last:mb-0">
   170→              <span
   171→                className="inline-flex items-center justify-center rounded-full shrink-0 mt-0.5"
   172→                style={{ backgroundColor: s.bg, border: `1px solid ${s.border}`, color: s.text, width: 16, height: 16 }}
   173→              >
   174→                <Icon size={9} />
   175→              </span>
   176→              <span className="flex flex-col">
   177→                <span className="text-[11px] font-semibold leading-tight" style={{ color: s.text }}>{label}</span>
   178→                <span className="text-[10px] leading-tight text-text-muted">{desc}</span>
   179→              </span>
   180→            </span>
   181→          );
   182→        })}
   183→      </span>
   184→    </span>
   185→  );
   186→}
   187→
   188→function ProjectFlowCard({ project }: { project: Project }) {
   189→  const { t } = useTranslation();
   190→  const [sourceCreateOpen, setSourceCreateOpen] = useState(false);
   191→  const [editingSource, setEditingSource] = useState<Source | null>(null);
   192→
   193→  const { data: srcData, mutate: mutateSources } = useSWR(
   194→    `project-${project.id}-card-sources`,
   195→    () => sourcesApi.listByProject(project.id),
   196→  );
   197→  const { data: relData } = useSWR(
   198→    `project-${project.id}-card-releases`,
   199→    () => releasesApi.listByProject(project.id, 1, 25, true),
   200→  );
   201→  const { data: srData } = useSWR(
   202→    `project-${project.id}-card-sr`,
   203→    () => srApi.list(project.id, 1, 10),
   204→  );
   205→
   206→  const sources = srcData?.data ?? [];
   207→  const releases = relData?.data ?? [];
   208→  const srItems = srData?.data ?? [];
   209→
   210→  const sourceMap = useMemo(() => {
   211→    const m = new Map<string, Source>();
   212→    for (const s of sources) m.set(s.id, s);
   213→    return m;
   214→  }, [sources]);
   215→
   216→  return (
   217→    <div
   218→      className="rounded-md px-5 py-4 border-border bg-surface"
   219→      style={{ border: "1px solid var(--border)" }}
   220→    >
   221→      {/* Header */}
   222→      <div className="flex items-center justify-between mb-2">
   223→        <div className="flex items-center gap-3 min-w-0">
   224→          <ProjectCardLogo projectId={project.id} name={project.name} />
   225→          <div className="min-w-0">
   226→            <Link
   227→              href={`/projects/${project.id}`}
   228→              className="group inline-flex items-center gap-1.5 text-[16px] font-bold transition-colors text-beacon-accent"
   229→              style={{ fontFamily: "var(--font-fraunces)" }}
   230→            >
   231→              {project.name}
   232→              <ArrowRight className="h-3.5 w-3.5 opacity-0 -translate-x-1 transition-all group-hover:opacity-100 group-hover:translate-x-0" />
   233→            </Link>
   234→            {project.description && (
   235→              <p
   236→                className="text-[13px] truncate text-text-secondary"
   237→                style={{ fontFamily: "var(--font-dm-sans)" }}
   238→              >
   239→                {project.description}
   240→              </p>
   241→            )}
   242→          </div>
   243→        </div>
   244→      </div>
   245→
   246→      {/* Sources chips */}
   247→      <div className="flex flex-wrap items-center gap-1.5 mb-3">
   248→        <span
   249→          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-0.5 text-text-muted"
   250→          style={{ fontFamily: "var(--font-dm-sans)" }}
   251→        >
   252→          {t("projects.sources")}:
   253→        </span>
   254→        {sources.map((source) => (
   255→          <button
   256→            key={source.id}
   257→            onClick={() => setEditingSource(source)}
   258→            className="group/chip inline-flex items-center gap-1.5 rounded px-2 py-0.5 text-[12px] transition-colors hover:bg-mono-bg"
   259→            style={{
   260→              backgroundColor: source.last_error ? "var(--error-bg)" : "var(--background)",
   261→              border: `1px solid ${source.last_error ? "var(--error-border)" : "var(--border)"}`,
   262→            }}
   263→            title={source.last_error ? `Error: ${source.last_error}` : undefined}
   264→          >
   265→            <span
   266→              className="inline-block h-1.5 w-1.5 rounded-full shrink-0"
   267→              style={{ backgroundColor: source.last_error ? "var(--error-text)" : source.enabled ? "var(--status-completed)" : "var(--text-muted)" }}
   268→            />
   269→            {(() => { const Icon = getProviderIcon(source.provider); return Icon ? <Icon size={12} className="shrink-0 text-text-muted" /> : null; })()}
   270→            <span className="text-secondary-foreground" style={{ fontFamily: "'JetBrains Mono', monospace" }}>
   271→              {source.repository}
   272→            </span>
   273→            {source.last_polled_at && (
   274→              <span className="text-text-muted">
   275→                {timeAgo(source.last_polled_at).replace(" ago", "")}
   276→              </span>
   277→            )}
   278→            <Pencil className="h-2.5 w-2.5 hidden group-hover/chip:inline shrink-0 text-text-muted opacity-50" />
   279→          </button>
   280→        ))}
   281→        <button
   282→          onClick={() => setSourceCreateOpen(true)}
   283→          className="inline-flex items-center gap-1 px-2 py-0.5 text-[12px] font-medium rounded border transition-colors hover:bg-mono-bg border-border text-text-muted"
   284→          style={{
   285→            fontFamily: "var(--font-dm-sans)",
   286→          }}
   287→        >
   288→          <Plus className="h-3 w-3" />
   289→          {t("projects.addSource")}
   290→        </button>
   291→      </div>
   292→
   293→      {/* Releases flow */}
   294→      {releases.length > 0 && (
   295→        <FlowSection label={t("projects.releases")} moreHref={`/releases?project=${project.id}`} moreLabel={t("projects.more")}>
   296→          {releases.map((r) => {
   297→            const src = sourceMap.get(r.source_id);
   298→            const matchingSr = srItems.find((sr) => sr.version === r.version);
   299→            return (
   300→              <span key={r.id} className="inline-flex items-baseline mr-2.5">
   301→                <Link
   302→                  href={`/releases/${r.id}`}
   303→                  className={r.excluded ? "" : "text-[#2563eb] hover:underline"}
   304→                  style={{
   305→                    fontFamily: "'JetBrains Mono', monospace",
   306→                    fontSize: "12px",
   307→                    ...(r.excluded ? { color: "var(--text-muted)" } : {}),
   308→                  }}
   309→                >
   310→                  {r.version}
   311→                </Link>
   312→                {!r.excluded && matchingSr?.status === "completed" && (() => {
   313→                  const pill = matchingSr.report?.urgency
   314→                    ? URGENCY_STYLES[matchingSr.report.urgency.toLowerCase()]
   315→                    : undefined;
   316→                  return pill ? (
   317→                    <Link
   318→                      href={`/projects/${project.id}/semantic-releases/${matchingSr.id}`}
   319→                      className="inline-flex items-center justify-center rounded-full ml-1 transition-colors"
   320→                      style={{ backgroundColor: pill.bg, border: `1px solid ${pill.border}`, color: pill.text, width: 18, height: 18 }}
   321→                      title={`${matchingSr.report!.urgency} — ${t("projects.viewReport")}`}
   322→                    >
   323→                      <pill.icon size={10} />
   324→                    </Link>
   325→                  ) : (
   326→                    <Link
   327→                      href={`/projects/${project.id}/semantic-releases/${matchingSr.id}`}
   328→                      className="inline-flex items-center gap-0.5 rounded-full px-2 py-0.5 ml-1 text-[10px] font-semibold transition-colors bg-muted text-text-secondary"
   329→                      style={{ border: "1px solid rgba(107,114,128,0.18)", fontFamily: "var(--font-dm-sans)" }}
   330→                      title={t("projects.viewReport")}
   331→                    >
   332→                      {t("projects.report")}
   333→                    </Link>
   334→                  );
   335→                })()}
   336→                {!r.excluded && (matchingSr?.status === "pending" || matchingSr?.status === "processing") && (
   337→                  <span
   338→                    className="inline-flex items-center gap-0.5 rounded px-1 py-0.5 ml-1 text-[10px]"
   339→                    style={{ backgroundColor: "#fef9c3", color: "#92400e", fontFamily: "var(--font-dm-sans)" }}
   340→                  >
   341→                    <Loader2 size={10} className="animate-spin" />
   342→                  </span>
   343→                )}
   344→                {src && (
   345→                  <span
   346→                    className="text-[11px] ml-1 hidden sm:inline text-text-muted"
   347→                    style={r.excluded ? { opacity: 0.5 } : {}}
   348→                  >
   349→                    ({src.repository.split("/").pop()})
   350→                  </span>
   351→                )}
   352→                <span
   353→                  className="text-[11px] ml-1 text-text-muted"
   354→                  style={r.excluded ? { opacity: 0.5 } : {}}
   355→                >
   356→                  {timeAgo(r.released_at || r.created_at).replace(" ago", "")}
   357→                </span>
   358→              </span>
   359→            );
   360→          })}
   361→        </FlowSection>
   362→      )}
   363→
   364→      {/* Add Source dialog */}
   365→      <Dialog open={sourceCreateOpen} onOpenChange={setSourceCreateOpen}>
   366→        <DialogContent className="sm:max-w-lg">
   367→          <DialogHeader>
   368→            <DialogTitle>{t("projects.addSource")}</DialogTitle>
   369→          </DialogHeader>
   370→          <SourceForm
   371→            title={t("projects.addSource")}
   372→            projectId={project.id}
   373→            onSubmit={async (input) => {
   374→              const res = await sourcesApi.create(project.id, input);
   375→              if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
   376→            }}
   377→            onSuccess={() => {
   378→              setSourceCreateOpen(false);
   379→              mutateSources();
   380→            }}
   381→            onCancel={() => setSourceCreateOpen(false)}
