    24→
    25→  // Listen to SSE events and revalidate dashboard data on new releases
    26→  useEffect(() => {
    27→    let es: EventSource | null = null;
    28→    let retryTimer: ReturnType<typeof setTimeout> | null = null;
    29→
    30→    function connect() {
    31→      try {
    32→        es = new EventSource(`${SSE_BASE}/events`);
    33→        es.onmessage = () => {
    34→          // Revalidate all dashboard SWR keys on any event
    35→          mutate((key) => typeof key === "string" && (
    36→            key === "stats" ||
    37→            key.startsWith("trend-") ||
    38→            key === "unified-feed"
    39→          ), undefined, { revalidate: true });
    40→        };
    41→        es.onerror = () => {
    42→          es?.close();
    43→          retryTimer = setTimeout(connect, 5000);
    44→        };
    45→      } catch {
    46→        retryTimer = setTimeout(connect, 5000);
    47→      }
    48→    }
    49→
    50→    connect();
    51→    return () => {
    52→      es?.close();
    53→      if (retryTimer) clearTimeout(retryTimer);
    54→    };
    55→  }, []);
    56→
    57→  const hasProjects = !isLoading && projectsData?.data && projectsData.data.length > 0;
    58→
    59→  return (
    60→    <div className="space-y-6">
    61→      <h1
    62→        style={{
    63→          fontFamily: "var(--font-fraunces)",
    64→          fontSize: "24px",
    65→          fontWeight: 700,
    66→          color: "var(--foreground)",
    67→        }}
    68→      >
    69→        {t("dashboard.title")}
    70→      </h1>
    71→
    72→      {user?.github_login && user.github_login !== "dev" ? (
    73→        <SuggestionsSection showAuthTabs />
    74→      ) : (
    75→        <>
    76→          <DiscoverySection />
    77→          <SuggestionsSection />
    78→        </>
    79→      )}
    80→
    81→      {hasProjects ? (
    82→        <>
    83→          <StatsCards />
    84→          <div className="grid gap-4 lg:grid-cols-2">
    85→            <ReleaseTrendChart />
    86→            <UnifiedFeed />
    87→          </div>
    88→        </>
    89→      ) : isLoading ? (
    90→        <div
    91→          className="py-16 text-center text-text-secondary"
    92→          style={{
    93→            fontFamily: "var(--font-dm-sans)",
    94→            fontSize: "13px",
    95→          }}
    96→        >
    97→          {t("dashboard.loading")}
    98→        </div>
    99→      ) : (
   100→        <DashboardEmptyState />
   101→      )}
   102→    </div>
   103→  );
   104→}
