    32→    case "dockerhub":
    33→      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    34→    case "ecr-public":
    35→      return `https://gallery.ecr.aws/${repository}`;
    36→    case "gitlab":
    37→      return `https://gitlab.com/${repository}/-/releases/${version}`;
    38→    default:
    39→      return null;
    40→  }
    41→}
    42→
    43→/* ------------------------------------------------------------------ */
    44→/*  Page                                                               */
    45→/* ------------------------------------------------------------------ */
    46→
    47→export default function ReleasesPage() {
    48→  return (
    49→    <Suspense>
    50→      <ReleasesPageInner />
    51→    </Suspense>
    52→  );
    53→}
    54→
    55→function ReleasesPageInner() {
    56→  const { t } = useTranslation();
    57→  const searchParams = useSearchParams();
    58→  const initialProject = searchParams.get("project") ?? "all";
    59→  const initialShowExcluded = searchParams.get("show_excluded") !== "false";
    60→  const [page, setPage] = useState(1);
    61→  const [projectFilter, setProjectFilter] = useState<string>(initialProject);
    62→  const [showExcluded, setShowExcluded] = useState(initialShowExcluded);
    63→  const [triggeringVersion, setTriggeringVersion] = useState<string | null>(null);
    64→
    65→  /* Fetch projects for the filter dropdown */
    66→  const { data: projectsData } = useSWR("projects-for-filter", async () => {
    67→    const firstPage = await projectsApi.list(1, 100);
    68→    return firstPage;
    69→  });
    70→
    71→  /* Fetch releases — scoped by project or all */
    72→  const { data: scopedData, isLoading: scopedLoading } = useSWR(
    73→    projectFilter !== "all" ? ["releases", page, projectFilter, showExcluded] : null,
    74→    () => releasesApi.listByProject(projectFilter, page, PER_PAGE, showExcluded)
    75→  );
    76→
    77→  const { data: allReleasesData, isLoading: allLoading } = useSWR(
    78→    projectFilter === "all" ? ["all-releases", page, showExcluded] : null,
    79→    () => releasesApi.list(page, PER_PAGE, showExcluded)
    80→  );
    81→
    82→  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
    83→
    84→  /* Releases come pre-enriched with project/source metadata from the backend */
    85→  const releases: Release[] =
    86→    projectFilter !== "all"
    87→      ? scopedData?.data ?? []
    88→      : allReleasesData?.data ?? [];
    89→
    90→  /* Pagination math */
    91→  const activeData = projectFilter !== "all" ? scopedData : allReleasesData;
    92→  const total = activeData?.meta?.total ?? 0;
    93→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
    94→  const startRow = (page - 1) * PER_PAGE + 1;
    95→  const endRow = Math.min(page * PER_PAGE, total);
    96→
    97→  /* SSE revalidation — refresh on semantic_release events */
    98→  const revalidateReleases = useCallback(() => {
    99→    return mutate((key) => {
   100→      if (Array.isArray(key)) {
   101→        return key[0] === "releases" || key[0] === "all-releases";
   102→      }
   103→      return false;
   104→    }, undefined, { revalidate: true });
   105→  }, []);
   106→
   107→  useEffect(() => {
   108→    let es: EventSource | null = null;
   109→    let retryTimer: ReturnType<typeof setTimeout> | null = null;
   110→
   111→    function connect() {
   112→      try {
   113→        es = new EventSource(`${SSE_BASE}/events`);
   114→        es.onmessage = (event) => {
   115→          try {
   116→            const parsed = JSON.parse(event.data);
   117→            if (parsed.type === "semantic_release") {
   118→              setTriggeringVersion(null);
   119→              revalidateReleases();
   120→            }
   121→          } catch {
   122→            // ignore parse errors
   123→          }
   124→        };
   125→        es.onerror = () => {
   126→          es?.close();
   127→          retryTimer = setTimeout(connect, 5000);
   128→        };
   129→      } catch {
   130→        retryTimer = setTimeout(connect, 5000);
   131→      }
   132→    }
   133→
   134→    connect();
   135→    return () => {
   136→      es?.close();
   137→      if (retryTimer) clearTimeout(retryTimer);
   138→    };
   139→  }, [revalidateReleases]);
   140→
   141→  /* Trigger agent run — keep spinner until SWR revalidation brings back the new status */
   142→  const handleTrigger = async (projectId: string, version: string) => {
   143→    setTriggeringVersion(version);
   144→    try {
   145→      await agent.triggerRun(projectId, version);
   146→      await revalidateReleases();
   147→    } catch {
   148→      setTriggeringVersion(null);
   149→    }
   150→  };
   151→
   152→  const tableHeaders = [
   153→    t("releases.col.project"),
   154→    t("releases.col.provider"),
   155→    t("releases.col.repository"),
   156→    t("releases.col.version"),
   157→    t("releases.col.released"),
   158→    t("releases.col.age"),
   159→    t("releases.col.report"),
   160→    "",
   161→  ];
   162→
   163→  return (
   164→    <div className="space-y-6">
   165→      {/* Page title */}
   166→      <h1
   167→        style={{
