   190→          }}
   191→          className="appearance-none rounded-md bg-surface px-3 py-2 pr-8 outline-none transition-shadow"
   192→          style={{
   193→            fontFamily: "var(--font-dm-sans)",
   194→            fontSize: "13px",
   195→            color: "var(--foreground)",
   196→            border: "1px solid var(--border)",
   197→          }}
   198→          onFocus={(e) =>
   199→            (e.currentTarget.style.boxShadow = "0 0 0 2px color-mix(in srgb, var(--beacon-accent) 25%, transparent)")
   200→          }
   201→          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
   202→        >
   203→          <option value="all">{t("releases.allProjects")}</option>
   204→          {projectsData?.data.map((p: Project) => (
   205→            <option key={p.id} value={p.id}>
   206→              {p.name}
   207→            </option>
   208→          ))}
   209→        </select>
   210→
   211→        <label className="inline-flex items-center gap-2 cursor-pointer select-none">
   212→          <span style={{
   213→            fontFamily: "var(--font-dm-sans)",
   214→            fontSize: "13px",
   215→            color: "var(--text-secondary)",
