   381→                        : "\u2014"}
   382→                    </span>
   383→                  </td>
   384→
   385→                  {/* Age */}
   386→                  <td className="px-4 py-3">
   387→                    <span
   388→                      style={{
   389→                        fontFamily: "var(--font-dm-sans)",
   390→                        fontSize: "13px",
   391→                        color: "var(--text-muted)",
   392→                      }}
   393→                    >
   394→                      {timeAgo(release.released_at ?? release.created_at)}
   395→                    </span>
   396→                  </td>
   397→
   398→                  {/* Report */}
   399→                  <td className="px-4 py-3">
   400→                    {release.semantic_release_status === "completed" && release.semantic_release_id && release.project_id ? (() => {
   401→                      const pill = release.semantic_release_urgency
   402→                        ? URGENCY_STYLES[release.semantic_release_urgency.toLowerCase()]
