   407→                          className="inline-flex items-center gap-0.5 rounded-full px-2 py-0.5 text-[10px] font-semibold transition-colors"
   408→                          style={{ backgroundColor: pill.bg, border: `1px solid ${pill.border}`, color: pill.text, fontFamily: "var(--font-dm-sans)" }}
   409→                          title={t("releases.viewReport")}
   410→                        >
   411→                          <pill.icon size={10} /> {release.semantic_release_urgency}
   412→                        </Link>
   413→                      ) : (
   414→                        <Link
   415→                          href={`/projects/${release.project_id}/semantic-releases/${release.semantic_release_id}`}
   416→                          className="inline-flex items-center gap-0.5 rounded-full px-2 py-0.5 text-[10px] font-semibold transition-colors bg-muted"
   417→                          style={{ border: "1px solid color-mix(in srgb, var(--text-secondary) 18%, transparent)", color: "var(--text-secondary)", fontFamily: "var(--font-dm-sans)" }}
   418→                          title={t("releases.viewReport")}
   419→                        >
   420→                          {t("releases.report")}
   421→                        </Link>
   422→                      );
   423→                    })() : release.semantic_release_status === "pending" || release.semantic_release_status === "processing" || triggeringVersion === release.version ? (
   424→                      <span
   425→                        className="inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[10px] font-semibold"
   426→                        style={{ color: "#2563eb", backgroundColor: "rgba(37,99,235,0.08)", border: "1px solid rgba(37,99,235,0.18)", fontFamily: "var(--font-dm-sans)" }}
   427→                      >
   428→                        <Loader2 size={10} className="animate-spin" />
   429→                        {release.semantic_release_status || t("releases.analyzing")}
   430→                      </span>
   431→                    ) : release.project_id && !release.excluded ? (
   432→                      <button
   433→                        onClick={() => handleTrigger(release.project_id!, release.version)}
   434→                        disabled={triggeringVersion === release.version}
   435→                        className="inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[10px] font-semibold transition-colors hover:bg-mono-bg disabled:opacity-50 cursor-pointer"
   436→                        style={{
   437→                          color: "var(--text-secondary)",
   438→                          backgroundColor: "color-mix(in srgb, var(--text-secondary) 6%, transparent)",
   439→                          border: "1px solid color-mix(in srgb, var(--text-secondary) 18%, transparent)",
   440→                          fontFamily: "var(--font-dm-sans)",
   441→                        }}
   442→                        title={t("releases.generateReport")}
   443→                      >
   444→                        <Sparkles size={10} />
   445→                        {t("releases.analyze")}
   446→                      </button>
   447→                    ) : (
   448→                      <span
   449→                        style={{
   450→                          fontFamily: "var(--font-dm-sans)",
   451→                          fontSize: "13px",
   452→                          color: "var(--text-muted)",
   453→                        }}
   454→                      >
   455→                        {"\u2014"}
   456→                      </span>
   457→                    )}
   458→                  </td>
   459→
   460→                  {/* Provider link */}
   461→                  <td className="px-4 py-3">
   462→                    {release.provider && release.repository && (() => {
   463→                      const url = getProviderUrl(release.provider, release.repository, release.version);
   464→                      return url ? (
   465→                        <a
   466→                          href={url}
   467→                          target="_blank"
   468→                          rel="noopener noreferrer"
   469→                          className="inline-flex items-center transition-colors hover:opacity-70"
   470→                          style={{ color: "var(--text-muted)" }}
   471→                          title={t("releases.viewOnProvider")}
   472→                        >
   473→                          <ExternalLink size={14} />
   474→                        </a>
   475→                      ) : null;
   476→                    })()}
   477→                  </td>
   478→                </tr>
   479→              ))}
   480→            </tbody>
   481→          </table>
   482→        )}
   483→      </div>
   484→
   485→      {/* Pagination */}
   486→      {total > 0 && (
   487→        <div className="flex items-center justify-between">
   488→          <span
   489→            style={{
   490→              fontFamily: "var(--font-dm-sans)",
   491→              fontSize: "13px",
   492→              color: "var(--text-muted)",
   493→            }}
   494→          >
   495→            {startRow}&ndash;{endRow} of {total}
   496→          </span>
   497→          <div className="flex items-center gap-2">
   498→            <button
   499→              disabled={page <= 1}
   500→              onClick={() => setPage(page - 1)}
   501→              className="rounded-md bg-surface px-3 py-1.5 transition-colors hover:bg-background disabled:cursor-not-allowed disabled:opacity-40"
   502→              style={{
   503→                fontFamily: "var(--font-dm-sans)",
   504→                fontSize: "13px",
   505→                color: "var(--secondary-foreground)",
   506→                border: "1px solid var(--border)",
   507→              }}
   508→            >
   509→              {t("releases.previous")}
   510→            </button>
   511→            <button
   512→              disabled={page >= totalPages}
   513→              onClick={() => setPage(page + 1)}
   514→              className="rounded-md bg-surface px-3 py-1.5 transition-colors hover:bg-background disabled:cursor-not-allowed disabled:opacity-40"
   515→              style={{
   516→                fontFamily: "var(--font-dm-sans)",
   517→                fontSize: "13px",
   518→                color: "var(--secondary-foreground)",
   519→                border: "1px solid var(--border)",
   520→              }}
   521→            >
   522→              {t("releases.next")}
   523→            </button>
   524→          </div>
   525→        </div>
   526→      )}
   527→    </div>
   528→  );
   529→}
   530→

