   209→                <span
   210→                  className="inline-flex items-center justify-center rounded-full px-1.5 text-[11px] font-medium leading-none"
   211→                  style={{
   212→                    minWidth: "18px",
   213→                    height: "18px",
   214→                    backgroundColor: isActive ? "var(--border)" : "var(--mono-bg)",
   215→                    color: isActive ? "var(--foreground)" : "var(--text-muted)",
   216→                  }}
   217→                >
   218→                  {counts[tab.key]}
   219→                </span>
   220→              </button>
   221→            );
   222→          })}
   223→        </div>
   224→
   225→        <button
   226→          onClick={() => {
   227→            setAggregated((v) => !v);
   228→            setPage(1);
   229→          }}
   230→          className="inline-flex items-center gap-1.5 rounded-md px-3 py-1.5 transition-colors"
   231→          style={{
   232→            fontFamily: "var(--font-dm-sans)",
   233→            fontSize: "13px",
   234→            fontWeight: 500,
   235→            color: aggregated ? "var(--foreground)" : "var(--text-secondary)",
   236→            backgroundColor: aggregated ? "var(--mono-bg)" : "transparent",
   237→            border: aggregated ? "1px solid var(--border)" : "1px solid transparent",
   238→          }}
   239→        >
   240→          {t("todo.latestOnly")}
   241→        </button>
   242→      </div>
   243→
   244→      {/* Table card */}
   245→      <div
   246→        className="overflow-hidden rounded-lg bg-surface"
   247→        style={{ border: "1px solid var(--border)" }}
   248→      >
   249→        {isLoading ? (
   250→          <div
   251→            className="py-16 text-center text-text-secondary"
   252→            style={{
   253→              fontFamily: "var(--font-dm-sans)",
   254→              fontSize: "13px",
   255→            }}
   256→          >
   257→            {t("todo.loading")}
   258→          </div>
   259→        ) : items.length === 0 ? (
   260→          <div className="py-16 text-center">
   261→            <p
   262→              className="text-text-muted"
   263→              style={{
   264→                fontFamily: "var(--font-fraunces)",
   265→                fontStyle: "italic",
   266→                fontSize: "15px",
   267→              }}
   268→            >
   269→              {t("todo.noItems").replace("{status}", tabLabelMap[activeTab])}
   270→            </p>
   271→          </div>
   272→        ) : (
   273→          <table className="w-full">
   274→            <thead>
   275→              <tr style={{ borderBottom: "1px solid var(--border)", backgroundColor: "var(--background)" }}>
   276→                {[t("todo.thProject"), t("todo.thVersion"), t("todo.thType"), t("todo.thProvider"), t("todo.thUrgency"), t("todo.thCreated"), t("todo.thActions")].map(
   277→                  (col) => (
   278→                    <th
   279→                      key={col}
   280→                      className="px-4 py-3 text-left"
   281→                      style={{
   282→                        fontFamily: "var(--font-dm-sans)",
   283→                        fontSize: "11px",
   284→                        fontWeight: 600,
   285→                        textTransform: "uppercase" as const,
   286→                        letterSpacing: "0.08em",
   287→                        color: "var(--text-muted)",
   288→                      }}
   289→                    >
   290→                      {col}
   291→                    </th>
   292→                  )
   293→                )}
   294→              </tr>
   295→            </thead>
   296→            <tbody>
   297→              {items.map((todo) => (
   298→                <tr
   299→                  key={todo.id}
   300→                  className="transition-colors hover:bg-background"
   301→                  style={{ borderBottom: "1px solid var(--border)" }}
   302→                >
   303→                  {/* Project */}
   304→                  <td className="px-4 py-3">
   305→                    <span
   306→                      className="text-foreground"
   307→                      style={{
   308→                        fontFamily: "var(--font-dm-sans)",
   309→                        fontSize: "13px",
   310→                        fontWeight: 500,
   311→                      }}
   312→                    >
   313→                      {todo.project_name ?? "\u2014"}
   314→                    </span>
   315→                  </td>
   316→
   317→                  {/* Version */}
   318→                  <td className="px-4 py-3">
   319→                    {todo.version ? (
   320→                      <Link
   321→                        href={
   322→                          todo.todo_type === "semantic" && todo.semantic_release_id && todo.project_id
   323→                            ? `/projects/${todo.project_id}/semantic-releases/${todo.semantic_release_id}`
   324→                            : todo.release_id
   325→                              ? `/releases/${todo.release_id}`
   326→                              : "#"
   327→                        }
   328→                      >
   329→                        <VersionChip version={todo.version} />
   330→                      </Link>
   331→                    ) : (
   332→                      <span
   333→                        className="text-text-muted"
   334→                        style={{
   335→                          fontFamily: "var(--font-dm-sans)",
   336→                          fontSize: "13px",
   337→                        }}
   338→                      >
   339→                        {"\u2014"}
   340→                      </span>
   341→                    )}
   342→                  </td>
   343→
   344→                  {/* Type */}
   345→                  <td className="px-4 py-3">
   346→                    <span
   347→                      className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
   348→                      style={{
   349→                        backgroundColor: todo.todo_type === "semantic" ? "#ede9fe" : "#e0f2fe",
   350→                        color: todo.todo_type === "semantic" ? "#6d28d9" : "#0369a1",
   351→                      }}
   352→                    >
   353→                      {todo.todo_type === "semantic" ? t("todo.typeSemantic") : t("todo.typeRelease")}
   354→                    </span>
   355→                  </td>
   356→
   357→                  {/* Provider */}
   358→                  <td className="px-4 py-3">
   359→                    {todo.provider ? (
   360→                      <ProviderBadge provider={todo.provider} />
   361→                    ) : (
   362→                      <span
   363→                        className="text-text-muted"
   364→                        style={{
   365→                          fontFamily: "var(--font-dm-sans)",
   366→                          fontSize: "13px",
   367→                        }}
   368→                      >
   369→                        {"\u2014"}
   370→                      </span>
   371→                    )}
   372→                  </td>
   373→
   374→                  {/* Urgency */}
   375→                  <td className="px-4 py-3">
   376→                    {todo.urgency && todo.todo_type === "semantic" ? (
   377→                      <span
   378→                        className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
   379→                        style={{
   380→                          backgroundColor:
   381→                            URGENCY_COLORS[todo.urgency.toUpperCase()]?.bg ?? "var(--mono-bg)",
   382→                          color:
   383→                            URGENCY_COLORS[todo.urgency.toUpperCase()]?.text ?? "var(--secondary-foreground)",
   384→                        }}
   385→                      >
   386→                        {todo.urgency.toUpperCase()}
   387→                      </span>
   388→                    ) : (
   389→                      <span
   390→                        className="text-text-muted"
   391→                        style={{
   392→                          fontFamily: "var(--font-dm-sans)",
   393→                          fontSize: "13px",
   394→                        }}
   395→                      >
   396→                        {"\u2014"}
   397→                      </span>
   398→                    )}
   399→                  </td>
   400→
   401→                  {/* Created */}
   402→                  <td className="px-4 py-3">
   403→                    <span
   404→                      className="text-text-muted"
   405→                      style={{
   406→                        fontFamily: "var(--font-dm-sans)",
   407→                        fontSize: "13px",
   408→                      }}
   409→                    >
   410→                      {timeAgo(todo.created_at)}
   411→                    </span>
   412→                  </td>
   413→
   414→                  {/* Actions */}
   415→                  <td className="px-4 py-3">
   416→                    <div className="flex items-center gap-1.5">
   417→                      {activeTab === "pending" && (
   418→                        <>
   419→                          <button
   420→                            onClick={() => handleAcknowledge(todo.id)}
   421→                            className="rounded-md px-2.5 py-1 transition-colors hover:opacity-80"
   422→                            style={{
   423→                              fontFamily: "var(--font-dm-sans)",
   424→                              fontSize: "12px",
   425→                              fontWeight: 500,
   426→                              backgroundColor: "#dcfce7",
   427→                              color: "#166534",
   428→                              border: "1px solid #bbf7d0",
   429→                            }}
   430→                          >
   431→                            {t("todo.acknowledge")}
   432→                          </button>
   433→                          <button
   434→                            onClick={() =>
   435→                              setConfirmDialog({
   436→                                action: t("todo.dismiss"),
   437→                                projectName: todo.project_name,
   438→                                version: todo.version,
   439→                                onConfirm: () => handleResolve(todo.id, false),
   440→                              })
   441→                            }
   442→                            className="rounded-md px-2.5 py-1 transition-colors hover:opacity-80 text-text-secondary border-border"
   443→                            style={{
   444→                              fontFamily: "var(--font-dm-sans)",
   445→                              fontSize: "12px",
   446→                              fontWeight: 500,
   447→                              border: "1px solid var(--border)",
   448→                            }}
   449→                          >
   450→                            {t("todo.dismiss")}
   451→                          </button>
   452→                        </>
   453→                      )}
   454→                      {activeTab === "acknowledged" && (
   455→                        <>
   456→                          <button
   457→                            onClick={() => handleResolve(todo.id)}
   458→                            className="rounded-md px-2.5 py-1 transition-colors hover:opacity-80"
   459→                            style={{
   460→                              fontFamily: "var(--font-dm-sans)",
   461→                              fontSize: "12px",
   462→                              fontWeight: 500,
   463→                              backgroundColor: "#dbeafe",
   464→                              color: "#1e40af",
   465→                              border: "1px solid #bfdbfe",
   466→                            }}
   467→                          >
   468→                            {t("todo.resolve")}
   469→                          </button>
   470→                          <button
   471→                            onClick={() =>
   472→                              setConfirmDialog({
   473→                                action: t("todo.undo"),
   474→                                projectName: todo.project_name,
   475→                                version: todo.version,
   476→                                onConfirm: () => handleReopen(todo.id),
   477→                              })
   478→                            }
   479→                            className="rounded-md px-2.5 py-1 transition-colors hover:opacity-80 text-text-secondary"
   480→                            style={{
   481→                              fontFamily: "var(--font-dm-sans)",
   482→                              fontSize: "12px",
   483→                              fontWeight: 500,
   484→                              border: "1px solid var(--border)",
   485→                            }}
   486→                          >
   487→                            {t("todo.undo")}
   488→                          </button>
   489→                        </>
   490→                      )}
   491→                      {activeTab === "resolved" && (
   492→                        <button
   493→                          onClick={() =>
   494→                            setConfirmDialog({
   495→                              action: t("todo.reopen"),
   496→                              projectName: todo.project_name,
   497→                              version: todo.version,
   498→                              onConfirm: () => handleReopen(todo.id),
   499→                            })
   500→                          }
   501→                          className="rounded-md px-2.5 py-1 transition-colors hover:opacity-80 text-text-secondary"
   502→                          style={{
   503→                            fontFamily: "var(--font-dm-sans)",
   504→                            fontSize: "12px",
   505→                            fontWeight: 500,
   506→                            border: "1px solid var(--border)",
   507→                          }}
   508→                        >
   509→                          {t("todo.reopen")}
   510→                        </button>
   511→                      )}
   512→                    </div>
   513→                  </td>
   514→                </tr>
   515→              ))}
   516→            </tbody>
   517→          </table>
   518→        )}
   519→      </div>
   520→
   521→      {/* Pagination */}
   522→      {total > 0 && (
   523→        <div className="flex items-center justify-between">
   524→          <span
   525→            className="text-text-muted"
   526→            style={{
   527→              fontFamily: "var(--font-dm-sans)",
   528→              fontSize: "13px",
   529→            }}
   530→          >
   531→            {startRow}&ndash;{endRow} of {total}
   532→          </span>
   533→          <div className="flex items-center gap-2">
   534→            <button
   535→              disabled={page <= 1}
   536→              onClick={() => setPage(page - 1)}
   537→              className="rounded-md bg-surface px-3 py-1.5 transition-colors hover:bg-background disabled:cursor-not-allowed disabled:opacity-40 text-secondary-foreground border-border"
   538→              style={{
   539→                fontFamily: "var(--font-dm-sans)",
   540→                fontSize: "13px",
   541→                border: "1px solid var(--border)",
   542→              }}
   543→            >
   544→              {t("todo.previous")}
   545→            </button>
   546→            <button
   547→              disabled={page >= totalPages}
   548→              onClick={() => setPage(page + 1)}
   549→              className="rounded-md bg-surface px-3 py-1.5 transition-colors hover:bg-background disabled:cursor-not-allowed disabled:opacity-40 text-secondary-foreground border-border"
   550→              style={{
   551→                fontFamily: "var(--font-dm-sans)",
   552→                fontSize: "13px",
   553→                border: "1px solid var(--border)",
   554→              }}
   555→            >
   556→              {t("todo.next")}
   557→            </button>
   558→          </div>
   559→        </div>
   560→      )}
   561→      {/* Confirmation dialog */}
   562→      {confirmDialog && (
   563→        <div
   564→          className="fixed inset-0 z-50 flex items-center justify-center"
   565→          style={{ backgroundColor: "rgba(0,0,0,0.4)" }}
   566→          onClick={() => setConfirmDialog(null)}
   567→        >
   568→          <div
   569→            className="rounded-lg bg-surface p-6 shadow-xl"
   570→            style={{ maxWidth: "360px", width: "100%" }}
   571→            onClick={(e) => e.stopPropagation()}
   572→          >
   573→            <p
   574→              className="text-foreground"
   575→              style={{
   576→                fontFamily: "var(--font-dm-sans)",
   577→                fontSize: "14px",
   578→                fontWeight: 400,
   579→                marginBottom: "20px",
   580→                lineHeight: 1.6,
   581→              }}
   582→            >
   583→              {confirmDialog.action}{" "}
   584→              {confirmDialog.projectName && (
   585→                <span style={{ fontWeight: 600 }}>{confirmDialog.projectName}</span>
   586→              )}{" "}
   587→              <span
   588→                className="bg-mono-bg"
   589→                style={{
   590→                  fontFamily: "var(--font-mono, ui-monospace, monospace)",
   591→                  fontSize: "13px",
   592→                  borderRadius: "4px",
   593→                  padding: "1px 6px",
   594→                  color: "#6d28d9",
   595→                }}
   596→              >
   597→                {confirmDialog.version ?? t("todo.thisItem")}
   598→              </span>
   599→              ?
   600→            </p>
   601→            <div className="flex items-center justify-end gap-2">
   602→              <button
   603→                onClick={() => setConfirmDialog(null)}
   604→                className="rounded-md px-3 py-1.5 transition-colors hover:bg-mono-bg text-text-secondary"
   605→                style={{
   606→                  fontFamily: "var(--font-dm-sans)",
   607→                  fontSize: "13px",
   608→                  border: "1px solid var(--border)",
   609→                }}
   610→              >
   611→                {t("todo.cancel")}
   612→              </button>
